r_mwa_book_loan_norm_nest.sql:
SELECT seq_no ,ref_own_no ,collateral_description ,coll_id_card ,collateral_type_code ,remark FROM(select sc_lon_m_req_coll.seq_no ,decode(sc_lon_m_req_coll.collateral_type_code,'03',pka_com_function.fp_form_depno(sc_lon_m_req_coll.ref_own_no) ,decode(sc_lon_m_req_coll.collateral_type_code,'08',pka_com_function.fp_form(sc_lon_m_req_coll.ref_own_no,'X-XXXX-XXXXX-XX-X'),sc_lon_m_req_coll.ref_own_no)) as ref_own_no ,sc_lon_m_req_coll.collateral_description ,pka_com_function.fp_get_member_id_card(sc_lon_m_req_coll.ref_own_no) as coll_id_card ,sc_lon_m_req_coll.collateral_type_code ,sc_lon_m_req_coll.remark from sc_lon_m_req_coll, sc_lon_m_loan_request where sc_lon_m_loan_request.loan_requestment_no = sc_lon_m_req_coll.loan_requestment_no and sc_lon_m_req_coll.collateral_type_code in ('01','02','03','08') and sc_lon_m_req_coll.loan_requestment_no = {0}
union all
select 99 as seq_no ,'' as ref_own_no ,''as collateral_description ,''as coll_id_card ,''as collateral_type_code ,''as remark from sc_lon_m_rule where 1=1 ) tb_coll where rownum <=8 order by seq_no
